#pragma once

#include <memory>

using std::shared_ptr;

// Базовый класс напитка
class Drink {
public:
    virtual ~Drink() = default;
    virtual double cost() const = 0;
};

// Базовый кофе
class Coffee : public Drink {
public:
    double cost() const override {
        return 1.0;
    }
};

// Базовый декоратор
class DrinkDecorator : public Drink {
protected:
    shared_ptr<Drink> beverage;

public:
    explicit DrinkDecorator(shared_ptr<Drink> b)
        : beverage(std::move(b)) {}

    double cost() const override {
        return beverage->cost();
    }
};

// Декоратор с молоком
class Milk : public DrinkDecorator {
public:
    explicit Milk(shared_ptr<Drink> b)
        : DrinkDecorator(std::move(b)) {}

    double cost() const override {
        return 0.5 + beverage->cost();
    }
};

// Декоратор с сахаром
class Sugar : public DrinkDecorator {
public:
    explicit Sugar(shared_ptr<Drink> b)
        : DrinkDecorator(std::move(b)) {}

    double cost() const override {
        return 0.2 + beverage->cost();
    }
};

